// Simple per-container log dir monitor (mock)
const {execSync} = require('child_process');
const threshold = 500*1024*1024;
const containers = ['ct1','ct2','ct3'];
containers.forEach(ct=>{
  const dir = `/var/log/${ct}`;
  try {
    const out = execSync(`du -sb ${dir}`).toString().trim();
    const size = parseInt(out.split('\t')[0],10);
    if(size>threshold) console.log(`${ct} over limit: ${size}`);
  } catch(e){}
});
```

